item.command:
$patterns = @(
  'BlarAI\\tools\\vikunja_mcp',
  'BlarAI\\tools\\autonomy_budget',
  'BlarAI\\tools\\scheduled-tasks',
  'BlarAI\\tools\\fleet_observability',
  'BlarAI\\tools\\fleet_ops',
  'BlarAI\\tools\\agents.ps1',
  'BlarAI\\.venv'
);
$files = Get-ChildItem -Recurse C:\Users\mrbla\devplatform\docs\scheduled\wake_templates -File;
foreach ($f in $files) {
  $c = Get-Content -Raw $f.FullName;
  foreach ($p in $patterns) {
    $newP = $p -replace 'BlarAI', 'devplatform';
    $c = $c -replace [regex]::Escape($p), $newP;
  }
  Set-Content -Path $f.FullName -Value $c -Encoding UTF8;
}

$scripts = @(
  'wake_launcher.ps1',
  'agents-cadence-monitor.ps1',
  'la_merge_approve.ps1',
  'escalation_watchdog.ps1',
  'toast_watchdog.ps1'
)
$hits = @()
foreach ($s in $scripts) {
  $p = "C:\Users\mrbla\devplatform\tools\scheduled-tasks\$s"
  if (-not (Test-Path $p)) { Write-Host "SKIP (missing): $s"; continue }
  $matches = Select-String -Path $p -Pattern 'C:\\Users\\mrbla\\BlarAI(?!\-worktrees)' -AllMatches
  foreach ($m in $matches) { $hits += [PSCustomObject]@{ Script=$s; Line=$m.LineNumber; Text=$m.Line.Trim() } }
}
$hits | Format-Table -AutoSize -Wrap

# (a) Look for any scheduled task referencing vikunja, anywhere in the task tree
$tasks = Get-ScheduledTask | Where-Object { ($_ | Export-ScheduledTask) -match 'vikunja' }
if ($tasks) {
  Write-Host "Vikunja-related scheduled tasks found:" -ForegroundColor Yellow
  $tasks | Select-Object TaskPath, TaskName, State | Format-Table -AutoSize
  foreach ($t in $tasks) {
    $xml = $t | Export-ScheduledTask
    if ($xml -match 'C:\\Users\\mrbla\\BlarAI') {
      throw "Task '$($t.TaskName)' at '$($t.TaskPath)' still references BlarAI. Repoint manually (Export-ScheduledTask -> rewrite -> Register-ScheduledTask) before completing Stage 4."
    }
  }
} else {
  Write-Host "No vikunja-related scheduled tasks (OK if autostart is via .lnk only — confirmed in 4.9)."
}
# (b) Confirm 4.9 actually touched something — if no vikunja .lnk and no scheduled task, autostart is missing entirely
$startup = "$env:APPDATA\Microsoft\Windows\Start Menu\Programs\Startup"
$vikLnk = Get-ChildItem $startup -Filter '*.lnk' -ErrorAction SilentlyContinue | Where-Object {
  $sc = (New-Object -ComObject WScript.Shell).CreateShortcut($_.FullName); $sc.TargetPath -match 'vikunja'
}
if (-not $tasks -and -not $vikLnk) {
  Write-Warning "No Vikunja autostart found (neither scheduled task nor Startup .lnk). On next reboot, Vikunja will NOT start automatically. Confirm with Lead Architect whether this is intentional."
}

Get-Process -Name "Claude","Code" -ErrorAction SilentlyContinue | Stop-Process -Force;
Get-CimInstance Win32_Process -Filter "Name = 'python.exe'" |
  Where-Object { $_.CommandLine -match 'vikunja_mcp' } |
  ForEach-Object { Stop-Process -Id $_.ProcessId -Force }

# 1. Re-verify Vikunja is stopped (defense in depth — Stage 0.4 may be days old)
$running = Get-Process -Name "vikunja*" -ErrorAction SilentlyContinue
if ($running) { throw "Vikunja is still running. Stop it before migrating the DB." }

$src = "C:\Users\mrbla\BlarAI\tools\vikunja\vikunja.db"
$dst = "C:\Users\mrbla\devplatform\tools\vikunja\vikunja.db"
$bak = "$src.cutover_bak"

if (-not (Test-Path $src)) { throw "Source DB not found at $src — confirm path before proceeding." }
# 2. Clobber check
if (Test-Path $dst) { throw "Destination DB already exists at $dst. Refusing to overwrite. Investigate manually." }

# 3. Pre-move SHA256
$srcHash = (Get-FileHash $src -Algorithm SHA256).Hash
Write-Host "Pre-move SHA256: $srcHash"

# 4. Side-copy backup at the source location (so rollback = Move bak back)
Copy-Item $src $bak -Force

# 5. Move (preserves attributes; atomic on same volume)
Move-Item -Path $src -Destination $dst

# 6. Post-move SHA256
$dstHash = (Get-FileHash $dst -Algorithm SHA256).Hash
Write-Host "Post-move SHA256: $dstHash"
if ($srcHash -ne $dstHash) {
  # Rollback this single step
  Move-Item -Path $dst -Destination $src -Force
  throw "DB hash mismatch after move (src=$srcHash dst=$dstHash). Restored to source. ABORT stage."
}

# 7. Best-effort SQLite integrity check
$sqlite = Get-Command sqlite3.exe -ErrorAction SilentlyContinue
if ($sqlite) {
  $check = & sqlite3.exe $dst "PRAGMA integrity_check;"
  if ($check -ne "ok") { throw "SQLite integrity_check returned: $check" }
  Write-Host "SQLite integrity_check: ok"
} else {
  Write-Host "sqlite3.exe not on PATH — skipping integrity_check (non-fatal)."
}

# 8. Move attachments dir if present (Vikunja default: tools/vikunja/files/)
$srcFiles = "C:\Users\mrbla\BlarAI\tools\vikunja\files"
$dstFiles = "C:\Users\mrbla\devplatform\tools\vikunja\files"
if (Test-Path $srcFiles) {
  if (Test-Path $dstFiles) { throw "Destination attachments dir already exists at $dstFiles." }
  Move-Item $srcFiles $dstFiles
}

# Record hash to STATUS.md per item 4.13
Write-Host "DB_HASH=$dstHash"

item.verify:
# Hardcoded Start-Sleep is unreliable for cold start with a sizable DB.
# Poll until reachable, with 30s deadline.
$deadline = (Get-Date).AddSeconds(30)
$ok = $false
while ((Get-Date) -lt $deadline) {
  try {
    Invoke-RestMethod -Uri "http://localhost:3456/api/v1/info" -TimeoutSec 2 -ErrorAction Stop | Out-Null
    $ok = $true; break
  } catch { Start-Sleep -Milliseconds 500 }
}
if (-not $ok) { throw "Vikunja did not become reachable within 30s. Check logs in tools/vikunja/." }
Write-Host "Vikunja reachable."

item.command:
if (-not $env:VIKUNJA_TOKEN) { Write-Error "Set \$env:VIKUNJA_TOKEN before running this step. See description for how to obtain a token."; return }
Invoke-RestMethod -Uri "http://localhost:3456/api/v1/projects" -Headers @{ Authorization = "Bearer $env:VIKUNJA_TOKEN" } |
  Select-Object id, title

item.verify:
Start-Sleep -Seconds 2
$proc = Get-CimInstance Win32_Process -Filter "Name = 'python.exe'" | Where-Object { $_.CommandLine -match 'devplatform.*tools\.vikunja_mcp\.bridge' }
if (-not $proc) { throw 'Bridge daemon failed to start from devplatform. Inspect tools/vikunja_mcp/bridge logs before proceeding to 4.7.' }
Write-Host "Bridge daemon running: PID $($proc.ProcessId)"

item.preflight:
# Resolve BLARAI_PID from the registry created in Stage 1.4 — do NOT hardcode.
$BLARAI_PID = (Get-Content C:\Users\mrbla\BlarAI\.platform\vikunja_project_ids.yaml | Select-String 'blarai_project_id:\s*(\d+)').Matches.Groups[1].Value
if (-not $BLARAI_PID) { throw 'BLARAI_PID not found in registry; complete Stage 1.4 first.' }

item.command:
function Enable-AndVerify-Task {
  param([string]$Name, [string]$Path = '\BlarAI\', [int]$TimeoutSec = 120)
  Enable-ScheduledTask -TaskName $Name -TaskPath $Path | Out-Null
  Start-ScheduledTask -TaskName $Name -TaskPath $Path
  $deadline = (Get-Date).AddSeconds($TimeoutSec)
  do {
    Start-Sleep -Seconds 2
    $info = Get-ScheduledTaskInfo -TaskName $Name -TaskPath $Path
  } while ($info.LastTaskResult -eq 267009 -and (Get-Date) -lt $deadline)
  if ($info.LastTaskResult -eq 267009) {
    Disable-ScheduledTask -TaskName $Name -TaskPath $Path | Out-Null
    throw "Task $Name still running after ${TimeoutSec}s. Auto-disabled. Investigate."
  }
  if ($info.LastTaskResult -ne 0) {
    Disable-ScheduledTask -TaskName $Name -TaskPath $Path | Out-Null
    throw "Task $Name failed with LastTaskResult=$($info.LastTaskResult). Auto-disabled. Investigate."
  }
  Write-Host "OK: $Name (LastRun=$($info.LastRunTime))"
}
# Run for the first task; repeat for each subsequent task in the order above.
# Real Title Case Spaces names — NOT 'BlarAI_wake_sdo' (that name does not exist in the live fleet).
Enable-AndVerify-Task -Name 'Wake SDO'
